SKILL = {'name': 'pdf_download_trigger', 'keywords': ['PDF generation', 'reportlab', 'button click', 'download', 'transcript', 'video data', 'file output'], 'prompt_fragment': 'Generate a PDF document with video metadata and transcripts when a download action is triggered. Validate input data, handle missing dependencies gracefully, and ensure the output file contains all required content. Use in-memory buffering for efficiency and provide fallback text generation when libraries are unavailable.', 'example_code': 'from typing import List, Dict, Any\nfrom io import BytesIO\n\ntry:\n    from reportlab.lib.pagesizes import letter\n    from reportlab.pdfgen import canvas\n    REPORTLAB_AVAILABLE = True\nexcept Exception:\n    REPORTLAB_AVAILABLE = False\n\ndef generate_pdf_with_transcripts(\n    video_data: List[Dict[str, Any]],\n    output_path: str = "output.pdf"\n) -> str:\n    if not video_data:\n        raise ValueError("video_data must not be empty")\n    required_keys = {"title", "info", "transcript"}\n    for idx, entry in enumerate(video_data):\n        missing = required_keys - set(entry.keys())\n        if missing:\n            raise ValueError(f"Entry at index {idx} missing keys: {missing}")\n    if REPORTLAB_AVAILABLE:\n        buffer = BytesIO()\n        c = canvas.Canvas(buffer, pagesize=letter)\n        width, height = letter\n        y = height - 50\n        for entry in video_data:\n            c.drawString(50, y, f"Title: {entry[\'title\']}")\n            y -= 20\n            c.drawString(50, y, f"Info: {entry[\'info\']}")\n            y -= 20\n            c.drawString(50, y, f"Transcript: {entry[\'transcript\']}")\n            y -= 40\n            if y < 100:\n                c.showPage()\n                y = height - 50\n        c.save()\n        buffer.seek(0)\n        with open(output_path, "wb") as f:\n            f.write(buffer.read())\n    else:\n        with open(output_path, "w", encoding="utf-8") as f:\n            f.write("%PDF-1.4\\n%% Generated by transcript pipeline\\n")\n            for entry in video_data:\n                f.write(f"Title: {entry[\'title\']}\\nInfo: {entry[\'info\']}\\nTranscript: {entry[\'transcript\']}\\n" + "-" * 40 + "\\n")\n    return output_path\n\ndef download_pdf_on_button_click(\n    video_data: List[Dict[str, Any]],\n    output_path: str = "download.pdf"\n) -> str:\n    return generate_pdf_with_transcripts(video_data, output_path)', 'language': 'python'}
